    if (nums.length === 1) {
        return 0;
    }

    // Sort the array to easily find min and max
    nums.sort((a, b) => a - b);

    // Try all possible subarrays of length >= 1
    let minRemovals = nums.length; // Worst case: remove all but one

    for (let i = 0; i < nums.length; i++) {
        // Try subarray starting at i with length from 1 to nums.length - i
        for (let j = i + 1; j <= nums.length; j++) {
            const subArr = nums.slice(i, j);
            const max = subArr[subArr.length - 1];
            const min = subArr[0];

