                // This subarray is balanced, so we can keep it
                // The number of elements to remove is (nums.length - subArr.length)
                minRemovals = Math.min(minRemovals, nums.length - subArr.length);
                break; // No need to check longer subarrays
            }
        }
    }

    return minRemovals;
}

